def fof_suggestions(spec: dict) -> list:
    """Suggest accounts to follow: followed by someone you follow, not you, not already followed; sorted."""
    users = set(spec["users"])
    who = spec["who"]
    if who not in users:
        return []
    adj = {}
    for f in spec["follows"]:
        if f[0] in users and f[1] in users:
            adj.setdefault(f[0], set()).add(f[1])
    direct = adj.get(who, set())
    sugg = set()
    for u in direct:
        sugg |= adj.get(u, set())
    sugg.discard(who)
    sugg -= direct
    return sorted(sugg)

